package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class CadastroActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_cadastro)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainCadastro)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<TextView>(R.id.txtVoltarLogin).setOnClickListener {
            finish()//fecha tela atual
        }

        findViewById<MaterialButton>(R.id.btnCriarContaCadastro).setOnClickListener {
            val nome = findViewById<TextInputEditText>(R.id.txtNome).text.toString().trim()
            val email = findViewById<TextInputEditText>(R.id.txtEmailCadastro).text.toString().trim()
            val senha = findViewById<TextInputEditText>(R.id.txtSenhaCadastro).text.toString()
            val confirmaSenha = findViewById<TextInputEditText>(R.id.txtConfirmarSenha).text.toString()

            // Validações
            when {
                nome.isEmpty() -> {
                    Toast.makeText(this, "Por favor, preencha o nome", Toast.LENGTH_SHORT).show()
                }
                email.isEmpty() -> {
                    Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_SHORT).show()
                }
                !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                    Toast.makeText(this, "Email inválido", Toast.LENGTH_SHORT).show()
                }
                senha.isEmpty() -> {
                    Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_SHORT).show()
                }
                senha.length < 6 -> {
                    Toast.makeText(this, "Senha deve ter pelo menos 6 caracteres", Toast.LENGTH_SHORT).show()
                }
                confirmaSenha.isEmpty() -> {
                    Toast.makeText(this, "Por favor, confirme a senha", Toast.LENGTH_SHORT).show()
                }
                senha != confirmaSenha -> {
                    Toast.makeText(this, "As senhas não coincidem", Toast.LENGTH_SHORT).show()
                }
                else -> {
                    try {
                        val db = DatabaseHelper(this)
                        val novoUser = User(nome = nome, email = email, password = senha)
                        val id = db.insertUser(novoUser)
                        if (id != -1L) {
                            // Mostrar AlertDialog de sucesso
                            AlertDialog.Builder(this)
                                .setTitle("Sucesso!")
                                .setMessage("Conta criada com sucesso! Agora faça login com suas credenciais.")
                                .setPositiveButton("OK") { _, _ ->
                                    // Navegar para MainActivity (tela de login)
                                    startActivity(Intent(this, MainActivity::class.java))
                                    finish()
                                }
                                .setCancelable(false)
                                .show()
                        } else {
                            Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_SHORT).show()
                        }
                    } catch (e: Exception) {
                        Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class CadastroActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_cadastro)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainCadastro)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<TextView>(R.id.txtVoltarLogin).setOnClickListener {
            finish()//fecha tela atual
        }

        findViewById<MaterialButton>(R.id.btnCriarContaCadastro).setOnClickListener {
            val nome = findViewById<TextInputEditText>(R.id.txtNome).text.toString().trim()
            val email = findViewById<TextInputEditText>(R.id.txtEmailCadastro).text.toString().trim()
            val senha = findViewById<TextInputEditText>(R.id.txtSenhaCadastro).text.toString()
            val confirmaSenha = findViewById<TextInputEditText>(R.id.txtConfirmarSenha).text.toString()

            // Validações
            var erroValidacao = false

            when {
                nome.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtNome).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o nome", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                email.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Email inválido"
                    Toast.makeText(this, "Email inválido", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.length < 6 -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Mínimo 6 caracteres"
                    Toast.makeText(this, "Senha deve ter pelo menos 6 caracteres", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                confirmaSenha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, confirme a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha != confirmaSenha -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Senhas não coincidem"
                    Toast.makeText(this, "As senhas não coincidem", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
            }

            // Se não houver erros, criar conta
            if (!erroValidacao) {
                try {
                    val db = DatabaseHelper(this)
                    val novoUser = User(nome = nome, email = email, password = senha)
                    val id = db.insertUser(novoUser)
                    if (id != -1L) {
                        // Mostrar AlertDialog de sucesso
                        AlertDialog.Builder(this)
                            .setTitle("Sucesso!")
                            .setMessage("Conta criada com sucesso! Agora faça login com suas credenciais.")
                            .setPositiveButton("OK") { _, _ ->
                                // Navegar para MainActivity (tela de login)
                                startActivity(Intent(this, MainActivity::class.java))
                                finish()
                            }
                            .setCancelable(false)
                            .show()
                    } else {
                        Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_LONG).show()
                    }
                } catch (e: Exception) {
                    Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
        }
    }
}

package com.example.projetomobile

import androidx.activity.OnBackPressedCallback
import android.os.Bundle
import android.text.InputType
import android.widget.ArrayAdapter
import android.widget.Button
import android.widget.EditText
import android.widget.LinearLayout
import android.widget.ListView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat

/**
 * Tela simples de administração para gestão de estoque (adicionar/editar/excluir produtos).
 * Implementação mínima: usa dialogs para operação sem criar layouts XML adicionais.
 */
class AdminActivity : AppCompatActivity() {
    private lateinit var productDb: ProductDatabaseHelper
    private lateinit var listView: ListView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        // Usar layout dedicado para admin
        setContentView(R.layout.activity_admin)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.tvAdminTitle)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        productDb = ProductDatabaseHelper(this)

        val btnMenu = findViewById<Button>(R.id.btnAdminMenu)
        btnMenu.setOnClickListener { showAdminMenu() }

        listView = findViewById(R.id.lstAdminProducts)
        refreshProductList()

        // Intercept back presses to show admin menu instead of closing
        onBackPressedDispatcher.addCallback(this, object : OnBackPressedCallback(true) {
            override fun handleOnBackPressed() {
                showAdminMenu()
            }
        })
    }

    private fun showAdminMenu() {
        val options = arrayOf("Listar produtos", "Adicionar produto", "Editar estoque", "Deletar produto", "Sair")
        AlertDialog.Builder(this)
            .setTitle("Painel Admin")
            .setItems(options) { dialog, which ->
                when (which) {
                    0 -> listProducts()
                    1 -> addProductDialog()
                    2 -> editStockDialog()
                    3 -> deleteProductDialog()
                    4 -> finish()
                }
            }
            .setCancelable(false)
            .show()
    }

    private fun listProducts() {
        // Atualiza a lista visível
        refreshProductList()
    }

    private fun refreshProductList() {
        val produtos = productDb.getAllProducts()
        val items = produtos.map { "${it.id}: ${it.nome} (estoque: ${it.estoque}) - R$ ${it.preco}" }
        val adapter = ArrayAdapter(this, android.R.layout.simple_list_item_1, items)
        listView.adapter = adapter
        listView.setOnItemClickListener { _, _, position, _ ->
            val prod = produtos[position]
            AlertDialog.Builder(this)
                .setTitle(prod.nome)
                .setMessage("ID: ${prod.id}\nPreço: R$ ${prod.preco}\nEstoque: ${prod.estoque}\nCategoria: ${prod.categoria}\n\nDescrição:\n${prod.descricao}")
                .setPositiveButton("Ok") { _, _ -> }
                .show()
        }
    }

    private fun addProductDialog() {
        val layout = LinearLayout(this)
        layout.orientation = LinearLayout.VERTICAL
        val nomeInput = EditText(this)
        nomeInput.hint = "Nome"
        val descInput = EditText(this)
        descInput.hint = "Descrição"
        val precoInput = EditText(this)
        precoInput.hint = "Preço"
        precoInput.inputType = InputType.TYPE_CLASS_NUMBER or InputType.TYPE_NUMBER_FLAG_DECIMAL
        val categoriaInput = EditText(this)
        categoriaInput.hint = "Categoria"
        val estoqueInput = EditText(this)
        estoqueInput.hint = "Estoque"
        estoqueInput.inputType = InputType.TYPE_CLASS_NUMBER

        layout.addView(nomeInput)
        layout.addView(descInput)
        layout.addView(precoInput)
        layout.addView(categoriaInput)
        layout.addView(estoqueInput)

        AlertDialog.Builder(this)
            .setTitle("Adicionar Produto")
            .setView(layout)
            .setPositiveButton("Salvar") { _, _ ->
                val nome = nomeInput.text.toString().trim()
                val descricao = descInput.text.toString().trim()
                val preco = precoInput.text.toString().toDoubleOrNull() ?: 0.0
                val categoria = categoriaInput.text.toString().trim().ifEmpty { "Geral" }
                val estoque = estoqueInput.text.toString().toIntOrNull() ?: 0

                if (nome.isEmpty()) {
                    Toast.makeText(this, "Nome é obrigatório.", Toast.LENGTH_LONG).show()
                    showAdminMenu()
                    return@setPositiveButton
                }

                val novo = Product(nome = nome, descricao = descricao, preco = preco, categoria = categoria, estoque = estoque)
                val id = productDb.insertProduct(novo)
                if (id != -1L) Toast.makeText(this, "Produto adicionado.", Toast.LENGTH_LONG).show()
                else Toast.makeText(this, "Erro ao adicionar produto.", Toast.LENGTH_LONG).show()
                showAdminMenu()
            }
            .setNegativeButton("Cancelar") { _, _ -> showAdminMenu() }
            .show()
    }

    private fun editStockDialog() {
        val produtos = productDb.getAllProducts()
        if (produtos.isEmpty()) {
            Toast.makeText(this, "Nenhum produto para editar.", Toast.LENGTH_LONG).show()
            showAdminMenu()
            return
        }
        val names = produtos.map { "${it.id}: ${it.nome} (estoque: ${it.estoque})" }.toTypedArray()
        AlertDialog.Builder(this)
            .setTitle("Escolha um produto")
            .setItems(names) { _, which ->
                val prod = produtos[which]
                val input = EditText(this)
                input.hint = "Novo estoque"
                input.inputType = InputType.TYPE_CLASS_NUMBER
                input.setText(prod.estoque.toString())
                AlertDialog.Builder(this)
                    .setTitle("Editar estoque - ${prod.nome}")
                    .setView(input)
                    .setPositiveButton("Salvar") { _, _ ->
                        val novoEstoque = input.text.toString().toIntOrNull() ?: prod.estoque
                        val atualizado = prod.copy(estoque = novoEstoque)
                        val rows = productDb.updateProduct(atualizado)
                        if (rows > 0) Toast.makeText(this, "Estoque atualizado.", Toast.LENGTH_LONG).show()
                        else Toast.makeText(this, "Erro ao atualizar estoque.", Toast.LENGTH_LONG).show()
                        showAdminMenu()
                    }
                    .setNegativeButton("Cancelar") { _, _ -> showAdminMenu() }
                    .show()
            }
            .setNegativeButton("Cancelar") { _, _ -> showAdminMenu() }
            .show()
    }

    private fun deleteProductDialog() {
        val produtos = productDb.getAllProducts()
        if (produtos.isEmpty()) {
            Toast.makeText(this, "Nenhum produto para deletar.", Toast.LENGTH_LONG).show()
            showAdminMenu()
            return
        }
        val names = produtos.map { "${it.id}: ${it.nome}" }.toTypedArray()
        AlertDialog.Builder(this)
            .setTitle("Escolha um produto para deletar")
            .setItems(names) { _, which ->
                val prod = produtos[which]
                AlertDialog.Builder(this)
                    .setTitle("Confirmar")
                    .setMessage("Deletar ${prod.nome} ?")
                    .setPositiveButton("Sim") { _, _ ->
                        val rows = productDb.deleteProduct(prod.id ?: -1L)
                        if (rows > 0) Toast.makeText(this, "Produto deletado.", Toast.LENGTH_LONG).show()
                        else Toast.makeText(this, "Erro ao deletar.", Toast.LENGTH_LONG).show()
                        showAdminMenu()
                    }
                    .setNegativeButton("Não") { _, _ -> showAdminMenu() }
                    .show()
            }
            .setNegativeButton("Cancelar") { _, _ -> showAdminMenu() }
            .show()
    }

    // Back press handled via OnBackPressedDispatcher callback
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class CadastroActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_cadastro)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainCadastro)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<TextView>(R.id.txtVoltarLogin).setOnClickListener {
            finish()//fecha tela atual
        }

        findViewById<MaterialButton>(R.id.btnCriarContaCadastro).setOnClickListener {
            val nome = findViewById<TextInputEditText>(R.id.txtNome).text.toString().trim()
            val email = findViewById<TextInputEditText>(R.id.txtEmailCadastro).text.toString().trim()
            val senha = findViewById<TextInputEditText>(R.id.txtSenhaCadastro).text.toString()
            val confirmaSenha = findViewById<TextInputEditText>(R.id.txtConfirmarSenha).text.toString()

            // Validações
            var erroValidacao = false

            when {
                nome.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtNome).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o nome", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                email.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Email inválido"
                    Toast.makeText(this, "Email inválido", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.length < 6 -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Mínimo 6 caracteres"
                    Toast.makeText(this, "Senha deve ter pelo menos 6 caracteres", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                confirmaSenha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, confirme a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha != confirmaSenha -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Senhas não coincidem"
                    Toast.makeText(this, "As senhas não coincidem", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
            }

            // Se não houver erros, criar conta
            if (!erroValidacao) {
                try {
                    val db = DatabaseHelper(this)
                    val novoUser = User(nome = nome, email = email, password = senha)
                    val id = db.insertUser(novoUser)
                    if (id != -1L) {
                        // Mostrar AlertDialog de sucesso
                        AlertDialog.Builder(this)
                            .setTitle("Sucesso!")
                            .setMessage("Conta criada com sucesso! Agora faça login com suas credenciais.")
                            .setPositiveButton("OK") { _, _ ->
                                // Navegar para MainActivity (tela de login)
                                startActivity(Intent(this, MainActivity::class.java))
                                finish()
                            }
                            .setCancelable(false)
                            .show()
                    } else {
                        Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_LONG).show()
                    }
                } catch (e: Exception) {
                    Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
        }
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class CadastroActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_cadastro)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainCadastro)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<TextView>(R.id.txtVoltarLogin).setOnClickListener {
            finish()//fecha tela atual
        }

        findViewById<MaterialButton>(R.id.btnCriarContaCadastro).setOnClickListener {
            val nome = findViewById<TextInputEditText>(R.id.txtNome).text.toString().trim()
            val email = findViewById<TextInputEditText>(R.id.txtEmailCadastro).text.toString().trim()
            val senha = findViewById<TextInputEditText>(R.id.txtSenhaCadastro).text.toString()
            val confirmaSenha = findViewById<TextInputEditText>(R.id.txtConfirmarSenha).text.toString()

            // Validações
            var erroValidacao = false

            when {
                nome.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtNome).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o nome", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                email.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Email inválido"
                    Toast.makeText(this, "Email inválido", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.length < 6 -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Mínimo 6 caracteres"
                    Toast.makeText(this, "Senha deve ter pelo menos 6 caracteres", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                confirmaSenha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, confirme a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha != confirmaSenha -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Senhas não coincidem"
                    Toast.makeText(this, "As senhas não coincidem", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
            }

            // Se não houver erros, criar conta
            if (!erroValidacao) {
                try {
                    // Perguntar se deseja criar conta de administrador
                    AlertDialog.Builder(this)
                        .setTitle("Tipo de conta")
                        .setMessage("Deseja criar uma conta de administrador?")
                        .setPositiveButton("Sim") { _, _ ->
                            // Solicitar código secreto para criar admin
                            val input = android.widget.EditText(this)
                            input.hint = "Código de administrador"
                            AlertDialog.Builder(this)
                                .setTitle("Código de administrador")
                                .setView(input)
                                .setPositiveButton("OK") { _, _ ->
                                    val codigo = input.text.toString().trim()
                                    if (codigo == "SUPERADMIN2026") {
                                        val userDb = UserDatabaseHelper(this)
                                        val novoUser = User(nome = nome, email = email, password = senha, role = "admin")
                                        val id = userDb.insertUser(novoUser)
                                        if (id != -1L) {
                                            AlertDialog.Builder(this)
                                                .setTitle("Sucesso!")
                                                .setMessage("Conta de administrador criada com sucesso. Faça login.")
                                                .setPositiveButton("OK") { _, _ ->
                                                    startActivity(Intent(this, MainActivity::class.java))
                                                    finish()
                                                }
                                                .setCancelable(false)
                                                .show()
                                        } else {
                                            Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_LONG).show()
                                        }
                                    } else {
                                        Toast.makeText(this, "Código inválido. Conta de administrador não criada.", Toast.LENGTH_LONG).show()
                                    }
                                }
                                .setNegativeButton("Cancelar", null)
                                .show()
                        }
                        .setNegativeButton("Não") { _, _ ->
                            try {
                                val userDb = UserDatabaseHelper(this)
                                val novoUser = User(nome = nome, email = email, password = senha)
                                val id = userDb.insertUser(novoUser)
                                if (id != -1L) {
                                    // Mostrar AlertDialog de sucesso
                                    AlertDialog.Builder(this)
                                        .setTitle("Sucesso!")
                                        .setMessage("Conta criada com sucesso! Agora faça login com suas credenciais.")
                                        .setPositiveButton("OK") { _, _ ->
                                            // Navegar para MainActivity (tela de login)
                                            startActivity(Intent(this, MainActivity::class.java))
                                            finish()
                                        }
                                        .setCancelable(false)
                                        .show()
                                } else {
                                    Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_LONG).show()
                                }
                            } catch (e: Exception) {
                                Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_LONG).show()
                            }
                        }
                        .show()
                } catch (e: Exception) {
                    Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
        }
    }
}

@file:Suppress("unused")
package com.example.projetomobile

import android.content.ContentValues
import android.content.Context
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper

class DatabaseHelper(context: Context) : SQLiteOpenHelper(context, DATABASE_NAME, null, DATABASE_VERSION) {
    companion object {
        const val DATABASE_NAME = "eco_verde.db"
        const val DATABASE_VERSION = 1

        // Tabela users
        const val TABLE_USER = "users"
        const val USER_COL_ID = "id"
        const val USER_COL_NOME = "nome"
        const val USER_COL_EMAIL = "email"
        const val USER_COL_PASSWORD = "password"

        private const val SQL_CREATE_TABLE_USER =
            "CREATE TABLE $TABLE_USER (" +
                    "$USER_COL_ID INTEGER PRIMARY KEY AUTOINCREMENT," +
                    "$USER_COL_NOME TEXT NOT NULL," +
                    "$USER_COL_EMAIL TEXT NOT NULL UNIQUE," +
                    "$USER_COL_PASSWORD TEXT NOT NULL" +
                    ")"
    }

    override fun onCreate(db: SQLiteDatabase) {
        db.execSQL(SQL_CREATE_TABLE_USER)

        // Criar usuário de teste para facilitar o desenvolvimento
        val values = ContentValues().apply {
            put(USER_COL_NOME, "Usuário Teste")
            put(USER_COL_EMAIL, "teste@example.com")
            put(USER_COL_PASSWORD, hashPassword("senha123"))
        }
        db.insert(TABLE_USER, null, values)
    }

    override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {
        db.execSQL("DROP TABLE IF EXISTS $TABLE_USER")
        onCreate(db)
    }

    // -------- Users CRUD simples (create + read) --------
    fun insertUser(user: User): Long {
        val db = writableDatabase
        val values = ContentValues().apply {
            put(USER_COL_NOME, user.nome)
            put(USER_COL_EMAIL, user.email)
            put(USER_COL_PASSWORD, hashPassword(user.password))
        }
        val id = db.insert(TABLE_USER, null, values)
        user.id = if (id == -1L) null else id
        db.close()
        return id
    }

    fun getUser(id: Long): User? {
        val db = readableDatabase
        val cursor = db.query(
            TABLE_USER,
            arrayOf(USER_COL_ID, USER_COL_NOME, USER_COL_EMAIL, USER_COL_PASSWORD),
            "$USER_COL_ID = ?",
            arrayOf(id.toString()),
            null,
            null,
            null
        )
        var user: User? = null
        if (cursor.moveToFirst()) {
            val uid = cursor.getLong(cursor.getColumnIndexOrThrow(USER_COL_ID))
            val nome = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_NOME))
            val email = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_EMAIL))
            val password = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_PASSWORD))
            user = User(uid, nome, email, password)
        }
        cursor.close()
        db.close()
        return user
    }

    fun getAllUsers(): List<User> {
        val users = mutableListOf<User>()
        val db = readableDatabase
        val cursor = db.query(
            TABLE_USER,
            arrayOf(USER_COL_ID, USER_COL_NOME, USER_COL_EMAIL, USER_COL_PASSWORD),
            null,
            null,
            null,
            null,
            "$USER_COL_NOME ASC"
        )
        if (cursor.moveToFirst()) {
            do {
                val uid = cursor.getLong(cursor.getColumnIndexOrThrow(USER_COL_ID))
                val nome = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_NOME))
                val email = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_EMAIL))
                val password = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_PASSWORD))
                users.add(User(uid, nome, email, password))
            } while (cursor.moveToNext())
        }
        cursor.close()
        db.close()
        return users
    }

    /**
     * Valida as credenciais do usuário (email e senha)
     * Retorna o usuário se as credenciais forem válidas, null caso contrário
     */
    fun authenticateUser(email: String, password: String): User? {
        val db = readableDatabase
        val cursor = db.query(
            TABLE_USER,
            arrayOf(USER_COL_ID, USER_COL_NOME, USER_COL_EMAIL, USER_COL_PASSWORD),
            "$USER_COL_EMAIL = ?",
            arrayOf(email),
            null,
            null,
            null
        )

        var user: User? = null
        if (cursor.moveToFirst()) {
            val uid = cursor.getLong(cursor.getColumnIndexOrThrow(USER_COL_ID))
            val nome = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_NOME))
            val userEmail = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_EMAIL))
            val hashedPassword = cursor.getString(cursor.getColumnIndexOrThrow(USER_COL_PASSWORD))

            // Verificar se a senha corresponde à hash armazenada
            if (hashPassword(password) == hashedPassword) {
                user = User(uid, nome, userEmail, hashedPassword)
            }
        }
        cursor.close()
        db.close()
        return user
    }

    // Simple SHA-256 hash for password storage. In production use a stronger salted hash (e.g. bcrypt).
    private fun hashPassword(password: String): String {
        val md = java.security.MessageDigest.getInstance("SHA-256")
        val bytes = md.digest(password.toByteArray(Charsets.UTF_8))
        return bytes.joinToString("") { "%02x".format(it) }
    }
}

@file:Suppress("unused") package com.example.projetomobile
import android.content.ContentValues import android.content.Context import android.database.sqlite.SQLiteDatabase import android.database.sqlite.SQLiteOpenHelper
/** * Gerencia a criação e versionamento do banco de dados. * As operações CRUD são delegadas para DatabaseHelpers específicas de cada entidade. */ class DatabaseHelper(context: Context) : SQLiteOpenHelper(context, DATABASE_NAME, null, DATABASE_VERSION) { companion object { const val DATABASE_NAME = "eco_verde.db" // bump version because schema changed (added role column) const val DATABASE_VERSION = 2
// Tabela users const val TABLE_USER = "users" const val USER_COL_ID = "id" const val USER_COL_NOME = "nome" const val USER_COL_EMAIL = "email" const val USER_COL_PASSWORD = "password" const val USER_COL_ROLE = "role"
private const val SQL_CREATE_TABLE_USER = "CREATE TABLE $TABLE_USER (" + "$USER_COL_ID INTEGER PRIMARY KEY AUTOINCREMENT," + "$USER_COL_NOME TEXT NOT NULL," + "$USER_COL_EMAIL TEXT NOT NULL UNIQUE," + "$USER_COL_PASSWORD TEXT NOT NULL," + "$USER_COL_ROLE TEXT NOT NULL DEFAULT 'user'" + ")"
// Tabela products const val TABLE_PRODUCT = "products" const val PRODUCT_COL_ID = "id" const val PRODUCT_COL_NOME = "nome" const val PRODUCT_COL_DESCRICAO = "descricao" const val PRODUCT_COL_PRECO = "preco" const val PRODUCT_COL_CATEGORIA = "categoria" const val PRODUCT_COL_ESTOQUE = "estoque" const val PRODUCT_COL_IMAGEM_URL = "imagem_url"
private const val SQL_CREATE_TABLE_PRODUCT = "CREATE TABLE $TABLE_PRODUCT (" + "$PRODUCT_COL_ID INTEGER PRIMARY KEY AUTOINCREMENT," + "$PRODUCT_COL_NOME TEXT NOT NULL," + "$PRODUCT_COL_DESCRICAO TEXT NOT NULL," + "$PRODUCT_COL_PRECO REAL NOT NULL," + "$PRODUCT_COL_CATEGORIA TEXT NOT NULL," + "$PRODUCT_COL_ESTOQUE INTEGER NOT NULL," + "$PRODUCT_COL_IMAGEM_URL TEXT" + ")" }
override fun onCreate(db: SQLiteDatabase) { db.execSQL(SQL_CREATE_TABLE_USER) db.execSQL(SQL_CREATE_TABLE_PRODUCT)
// Criar usuário de teste para facilitar o desenvolvimento val userValues = ContentValues().apply { put(USER_COL_NOME, "Usuário Teste") put(USER_COL_EMAIL, "teste@example.com") put(USER_COL_PASSWORD, hashPassword("senha123")) put(USER_COL_ROLE, "user") } db.insert(TABLE_USER, null, userValues)
// Criar produtos de teste val produtos = listOf( Product(nome = "Alface", descricao = "Alface fresca e crocante", preco = 6.90, categoria = "Vegetais", estoque = 50), Product(nome = "Tomate", descricao = "Tomate vermelho e suculento", preco = 8.50, categoria = "Vegetais", estoque = 40), Product(nome = "Morango", descricao = "Morango doce e saboroso", preco = 10.00, categoria = "Frutas", estoque = 30), Product(nome = "Cenoura", descricao = "Cenoura orgânica e nutritiva", preco = 5.50, categoria = "Vegetais", estoque = 60), Product(nome = "Maçã", descricao = "Maçã vermelha e crocante", preco = 7.00, categoria = "Frutas", estoque = 45), Product(nome = "Brócolis", descricao = "Brócolis fresco e verde", preco = 12.00, categoria = "Vegetais", estoque = 25) )
for (produto in produtos) { val productValues = ContentValues().apply { put(PRODUCT_COL_NOME, produto.nome) put(PRODUCT_COL_DESCRICAO, produto.descricao) put(PRODUCT_COL_PRECO, produto.preco) put(PRODUCT_COL_CATEGORIA, produto.categoria) put(PRODUCT_COL_ESTOQUE, produto.estoque) put(PRODUCT_COL_IMAGEM_URL, produto.imagemUrl) } db.insert(TABLE_PRODUCT, null, productValues) } }
override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) { db.execSQL("DROP TABLE IF EXISTS $TABLE_PRODUCT") db.execSQL("DROP TABLE IF EXISTS $TABLE_USER") onCreate(db) }
// Simple SHA-256 hash for password storage. In production use a stronger salted hash (e.g. bcrypt). private fun hashPassword(password: String): String { val md = java.security.MessageDigest.getInstance("SHA-256") val bytes = md.digest(password.toByteArray(Charsets.UTF_8)) return bytes.joinToString("") { "%02x".format(it) } } }

