import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_main)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.main)) { v, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            v.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<MaterialButton>(R.id.btnEntrar).setOnClickListener {
            validarLogin()
        }

        findViewById<TextView>(R.id.txtCriarConta).setOnClickListener {
            startActivity(Intent(this, CadastroActivity::class.java))
        }

        findViewById<TextView>(R.id.txtEsqueciSenha).setOnClickListener {
            startActivity(Intent(this, RecuperarSenhaActivity::class.java))
        }
    }

    private fun validarLogin() {
        val email = findViewById<TextInputEditText>(R.id.txtEmail).text.toString().trim()
        val senha = findViewById<TextInputEditText>(R.id.txtSenha).text.toString()

        // Validações
        var erroValidacao = false

        when {
            email.isEmpty() -> {
                findViewById<TextInputEditText>(R.id.txtEmail).error = "Campo obrigatório"
                Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_LONG).show()
                erroValidacao = true
            }
            !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                findViewById<TextInputEditText>(R.id.txtEmail).error = "Email inválido"
                Toast.makeText(this, "Email inválido", Toast.LENGTH_LONG).show()
                erroValidacao = true
            }
            senha.isEmpty() -> {
                findViewById<TextInputEditText>(R.id.txtSenha).error = "Campo obrigatório"
                Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_LONG).show()
                erroValidacao = true
            }
        }

        if (!erroValidacao) {
            try {
                val userDb = UserDatabaseHelper(this)
                val user = userDb.authenticateUser(email, senha)

                if (user != null) {
                    // Login bem-sucedido
                    // Salvar ID do usuário em SharedPreferences
                    val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
                    with(sharedPref.edit()) {
                        putLong("user_id", user.id ?: -1L)
                        putString("user_name", user.nome)
                        putString("user_email", user.email)
                        apply()
                    }

                    Toast.makeText(this, "Bem-vindo, ${user.nome}!", Toast.LENGTH_LONG).show()
                    // Navegar para HomeActivity ou AdminActivity conforme role
                    if (user.role == "admin") {
                        startActivity(Intent(this, AdminActivity::class.java))
                    } else {
                        startActivity(Intent(this, HomeActivity::class.java))
                    }
                    finish()
                } else {
                    // Email ou senha incorretos
                    Toast.makeText(this, "Email ou senha incorretos", Toast.LENGTH_LONG).show()
                    findViewById<TextInputEditText>(R.id.txtSenha).setText("")
                    findViewById<TextInputEditText>(R.id.txtSenha).requestFocus()
                }
            } catch (e: Exception) {
                Toast.makeText(this, "Erro ao fazer login: ${e.message}", Toast.LENGTH_LONG).show()
            }
        }
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.bottomnavigation.BottomNavigationView
import com.google.android.material.button.MaterialButton

class PerfilActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_perfil)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainPerfil)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        // Carregar dados do usuário logado
        carregarDadosUsuario()

        // Botão de logout
        findViewById<MaterialButton>(R.id.btnExcluirConta).setOnClickListener {
            mostrarDialogoLogout()
        }

        val bnvPerfil = findViewById<BottomNavigationView>(R.id.bnvPerfil)

        bnvPerfil.selectedItemId = R.id.menuPerfil
        bnvPerfil.setOnItemSelectedListener { item ->
            when (item.itemId) {
                R.id.menuProdutos -> {
                    startActivity(Intent(this, HomeActivity::class.java))
                    true
                }

                R.id.menuCarrinho -> {
                    startActivity(Intent(this, CarrinhoActivity::class.java))
                    true
                }

                R.id.menuPerfil -> true
                else -> false
            }
        }
    }

    private fun carregarDadosUsuario() {
        val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
        val userId = sharedPref.getLong("user_id", -1L)

        if (userId != -1L) {
            try {
                val db = DatabaseHelper(this)
                val user = db.getUser(userId)

                if (user != null) {
                    // Exibir dados do usuário
                    findViewById<TextView>(R.id.txtNomePerfil).text = user.nome
                    findViewById<TextView>(R.id.txtEmailPerfil).text = user.email
                    findViewById<TextView>(R.id.txtInfoPerfil).text = "ID do usuário: ${user.id}"
                } else {
                    // Usuário não encontrado, fazer logout
                    fazer_logout()
                }
            } catch (e: Exception) {
                Toast.makeText(this, "Erro ao carregar perfil: ${e.message}", Toast.LENGTH_LONG).show()
            }
        } else {
            // Nenhum usuário logado
            fazer_logout()
        }
    }

    private fun mostrarDialogoLogout() {
        AlertDialog.Builder(this)
            .setTitle("Logout")
            .setMessage("Tem certeza que deseja sair?")
            .setPositiveButton("Sim") { _, _ ->
                fazer_logout()
            }
            .setNegativeButton("Cancelar", null)
            .show()
    }

    private fun fazer_logout() {
        // Limpar dados do usuário
        val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
        with(sharedPref.edit()) {
            remove("user_id")
            remove("user_name")
            remove("user_email")
            apply()
        }

        // Voltar para MainActivity
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.bottomnavigation.BottomNavigationView
import com.google.android.material.button.MaterialButton

class PerfilActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_perfil)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainPerfil)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        // Carregar dados do usuário logado
        carregarDadosUsuario()

        // Botão de logout
        findViewById<MaterialButton>(R.id.btnExcluirConta).setOnClickListener {
            mostrarDialogoLogout()
        }

        val bnvPerfil = findViewById<BottomNavigationView>(R.id.bnvPerfil)

        bnvPerfil.selectedItemId = R.id.menuPerfil
        bnvPerfil.setOnItemSelectedListener { item ->
            when (item.itemId) {
                R.id.menuProdutos -> {
                    startActivity(Intent(this, HomeActivity::class.java))
                    true
                }

                R.id.menuCarrinho -> {
                    startActivity(Intent(this, CarrinhoActivity::class.java))
                    true
                }

                R.id.menuPerfil -> true
                else -> false
            }
        }
    }

    private fun carregarDadosUsuario() {
        val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
        val userId = sharedPref.getLong("user_id", -1L)

        if (userId != -1L) {
            try {
                val userDb = UserDatabaseHelper(this)
                val user = userDb.getUser(userId)

                if (user != null) {
                    // Exibir dados do usuário
                    findViewById<TextView>(R.id.txtNomePerfil).text = user.nome
                    findViewById<TextView>(R.id.txtEmailPerfil).text = user.email
                    findViewById<TextView>(R.id.txtInfoPerfil).text = "ID do usuário: ${user.id}"
                } else {
                    // Usuário não encontrado, fazer logout
                    fazer_logout()
                }
            } catch (e: Exception) {
                Toast.makeText(this, "Erro ao carregar perfil: ${e.message}", Toast.LENGTH_LONG).show()
            }
        } else {
            // Nenhum usuário logado
            fazer_logout()
        }
    }

    private fun mostrarDialogoLogout() {
        AlertDialog.Builder(this)
            .setTitle("Logout")
            .setMessage("Tem certeza que deseja sair?")
            .setPositiveButton("Sim") { _, _ ->
                fazer_logout()
            }
            .setNegativeButton("Cancelar", null)
            .show()
    }

    private fun fazer_logout() {
        // Limpar dados do usuário
        val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
        with(sharedPref.edit()) {
            remove("user_id")
            remove("user_name")
            remove("user_email")
            apply()
        }

        // Voltar para MainActivity
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }
}

package com.example.projetomobile
import android.content.ContentValues import android.content.Context
/** * DatabaseHelper específico para operações CRUD de Product. * Delegado pela classe DatabaseHelper que gerencia schema e versionamento. */ class ProductDatabaseHelper(context: Context) { private val dbHelper = DatabaseHelper(context)
/** * Insere um novo produto no banco de dados. * @param product Objeto Product a ser inserido * @return ID do produto inserido, ou -1 se falhar */ fun insertProduct(product: Product): Long { val db = dbHelper.writableDatabase val values = ContentValues().apply { put(DatabaseHelper.PRODUCT_COL_NOME, product.nome) put(DatabaseHelper.PRODUCT_COL_DESCRICAO, product.descricao) put(DatabaseHelper.PRODUCT_COL_PRECO, product.preco) put(DatabaseHelper.PRODUCT_COL_CATEGORIA, product.categoria) put(DatabaseHelper.PRODUCT_COL_ESTOQUE, product.estoque) put(DatabaseHelper.PRODUCT_COL_IMAGEM_URL, product.imagemUrl) } val id = db.insert(DatabaseHelper.TABLE_PRODUCT, null, values) product.id = if (id == -1L) null else id db.close() return id }
/** * Obtém um produto pelo ID. * @param id ID do produto * @return Objeto Product ou null se não encontrado */ fun getProduct(id: Long): Product? { val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_PRODUCT, arrayOf( DatabaseHelper.PRODUCT_COL_ID, DatabaseHelper.PRODUCT_COL_NOME, DatabaseHelper.PRODUCT_COL_DESCRICAO, DatabaseHelper.PRODUCT_COL_PRECO, DatabaseHelper.PRODUCT_COL_CATEGORIA, DatabaseHelper.PRODUCT_COL_ESTOQUE, DatabaseHelper.PRODUCT_COL_IMAGEM_URL ), "${DatabaseHelper.PRODUCT_COL_ID} = ?", arrayOf(id.toString()), null, null, null ) var product: Product? = null if (cursor.moveToFirst()) { val pid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_NOME)) val descricao = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_DESCRICAO)) val preco = cursor.getDouble(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_PRECO)) val categoria = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_CATEGORIA)) val estoque = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_ESTOQUE)) val imagemUrl = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_IMAGEM_URL)) product = Product(pid, nome, descricao, preco, categoria, estoque, imagemUrl) } cursor.close() db.close() return product }
/** * Obtém todos os produtos do banco. * @return Lista de produtos ordenados por nome */ fun getAllProducts(): List<Product> { val products = mutableListOf<Product>() val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_PRODUCT, arrayOf( DatabaseHelper.PRODUCT_COL_ID, DatabaseHelper.PRODUCT_COL_NOME, DatabaseHelper.PRODUCT_COL_DESCRICAO, DatabaseHelper.PRODUCT_COL_PRECO, DatabaseHelper.PRODUCT_COL_CATEGORIA, DatabaseHelper.PRODUCT_COL_ESTOQUE, DatabaseHelper.PRODUCT_COL_IMAGEM_URL ), null, null, null, null, "${DatabaseHelper.PRODUCT_COL_NOME} ASC" ) if (cursor.moveToFirst()) { do { val pid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_NOME)) val descricao = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_DESCRICAO)) val preco = cursor.getDouble(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_PRECO)) val categoria = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_CATEGORIA)) val estoque = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_ESTOQUE)) val imagemUrl = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_IMAGEM_URL)) products.add(Product(pid, nome, descricao, preco, categoria, estoque, imagemUrl)) } while (cursor.moveToNext()) } cursor.close() db.close() return products }
/** * Obtém produtos filtrados por categoria. * @param categoria Nome da categoria * @return Lista de produtos da categoria, ordenados por nome */ fun getProductsByCategory(categoria: String): List<Product> { val products = mutableListOf<Product>() val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_PRODUCT, arrayOf( DatabaseHelper.PRODUCT_COL_ID, DatabaseHelper.PRODUCT_COL_NOME, DatabaseHelper.PRODUCT_COL_DESCRICAO, DatabaseHelper.PRODUCT_COL_PRECO, DatabaseHelper.PRODUCT_COL_CATEGORIA, DatabaseHelper.PRODUCT_COL_ESTOQUE, DatabaseHelper.PRODUCT_COL_IMAGEM_URL ), "${DatabaseHelper.PRODUCT_COL_CATEGORIA} = ?", arrayOf(categoria), null, null, "${DatabaseHelper.PRODUCT_COL_NOME} ASC" ) if (cursor.moveToFirst()) { do { val pid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_NOME)) val descricao = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_DESCRICAO)) val preco = cursor.getDouble(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_PRECO)) val cat = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_CATEGORIA)) val estoque = cursor.getInt(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_ESTOQUE)) val imagemUrl = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_IMAGEM_URL)) products.add(Product(pid, nome, descricao, preco, cat, estoque, imagemUrl)) } while (cursor.moveToNext()) } cursor.close() db.close() return products }
/** * Atualiza os dados de um produto. * @param product Objeto Product com dados atualizados * @return Número de linhas afetadas */ fun updateProduct(product: Product): Int { val db = dbHelper.writableDatabase val values = ContentValues().apply { put(DatabaseHelper.PRODUCT_COL_NOME, product.nome) put(DatabaseHelper.PRODUCT_COL_DESCRICAO, product.descricao) put(DatabaseHelper.PRODUCT_COL_PRECO, product.preco) put(DatabaseHelper.PRODUCT_COL_CATEGORIA, product.categoria) put(DatabaseHelper.PRODUCT_COL_ESTOQUE, product.estoque) put(DatabaseHelper.PRODUCT_COL_IMAGEM_URL, product.imagemUrl) } val rowsAffected = db.update( DatabaseHelper.TABLE_PRODUCT, values, "${DatabaseHelper.PRODUCT_COL_ID} = ?", arrayOf(product.id.toString()) ) db.close() return rowsAffected }
/** * Deleta um produto pelo ID. * @param id ID do produto a deletar * @return Número de linhas afetadas */ fun deleteProduct(id: Long): Int { val db = dbHelper.writableDatabase val rowsAffected = db.delete( DatabaseHelper.TABLE_PRODUCT, "${DatabaseHelper.PRODUCT_COL_ID} = ?", arrayOf(id.toString()) ) db.close() return rowsAffected }
/** * Obtém todas as categorias únicas de produtos. * @return Lista de categorias */ fun getAllCategories(): List<String> { val categories = mutableListOf<String>() val db = dbHelper.readableDatabase val cursor = db.rawQuery( "SELECT DISTINCT ${DatabaseHelper.PRODUCT_COL_CATEGORIA} FROM ${DatabaseHelper.TABLE_PRODUCT} ORDER BY ${DatabaseHelper.PRODUCT_COL_CATEGORIA}", null ) if (cursor.moveToFirst()) { do { val categoria = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.PRODUCT_COL_CATEGORIA)) categories.add(categoria) } while (cursor.moveToNext()) } cursor.close() db.close() return categories } }

package com.example.projetomobile
import android.content.ContentValues import android.content.Context
/** * DatabaseHelper específico para operações CRUD de User. * Delegado pela classe DatabaseHelper que gerencia schema e versionamento. */ class UserDatabaseHelper(context: Context) { private val dbHelper = DatabaseHelper(context)
/** * Insere um novo usuário no banco de dados. * @param user Objeto User a ser inserido * @return ID do usuário inserido, ou -1 se falhar */ fun insertUser(user: User): Long { val db = dbHelper.writableDatabase val values = ContentValues().apply { put(DatabaseHelper.USER_COL_NOME, user.nome) put(DatabaseHelper.USER_COL_EMAIL, user.email) put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(user.password)) put(DatabaseHelper.USER_COL_ROLE, user.role) } val id = db.insert(DatabaseHelper.TABLE_USER, null, values) user.id = if (id == -1L) null else id db.close() return id }
/** * Obtém um usuário pelo ID. * @param id ID do usuário * @return Objeto User ou null se não encontrado */ fun getUser(id: Long): User? { val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_USER, arrayOf( DatabaseHelper.USER_COL_ID, DatabaseHelper.USER_COL_NOME, DatabaseHelper.USER_COL_EMAIL, DatabaseHelper.USER_COL_PASSWORD, DatabaseHelper.USER_COL_ROLE ), "${DatabaseHelper.USER_COL_ID} = ?", arrayOf(id.toString()), null, null, null ) var user: User? = null if (cursor.moveToFirst()) { val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME)) val email = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL)) val password = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD)) val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE)) user = User(uid, nome, email, password, role) } cursor.close() db.close() return user }
/** * Obtém todos os usuários do banco. * @return Lista de usuários ordenados por nome */ fun getAllUsers(): List<User> { val users = mutableListOf<User>() val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_USER, arrayOf( DatabaseHelper.USER_COL_ID, DatabaseHelper.USER_COL_NOME, DatabaseHelper.USER_COL_EMAIL, DatabaseHelper.USER_COL_PASSWORD, DatabaseHelper.USER_COL_ROLE ), null, null, null, null, "${DatabaseHelper.USER_COL_NOME} ASC" ) if (cursor.moveToFirst()) { do { val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME)) val email = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL)) val password = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD)) val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE)) users.add(User(uid, nome, email, password, role)) } while (cursor.moveToNext()) } cursor.close() db.close() return users }
/** * Autentica um usuário validando email e senha. * @param email Email do usuário * @param password Senha em texto plano * @return Objeto User se autenticado com sucesso, null caso contrário */ fun authenticateUser(email: String, password: String): User? { val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_USER, arrayOf( DatabaseHelper.USER_COL_ID, DatabaseHelper.USER_COL_NOME, DatabaseHelper.USER_COL_EMAIL, DatabaseHelper.USER_COL_PASSWORD, DatabaseHelper.USER_COL_ROLE ), "${DatabaseHelper.USER_COL_EMAIL} = ?", arrayOf(email), null, null, null )
var user: User? = null if (cursor.moveToFirst()) { val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME)) val userEmail = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL)) val hashedPassword = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD)) val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE))
// Verificar se a senha corresponde à hash armazenada if (hashPassword(password) == hashedPassword) { user = User(uid, nome, userEmail, hashedPassword, role) } } cursor.close() db.close() return user }
/** * Atualiza os dados de um usuário. * @param user Objeto User com dados atualizados * @return Número de linhas afetadas */ fun updateUser(user: User): Int { val db = dbHelper.writableDatabase val values = ContentValues().apply { put(DatabaseHelper.USER_COL_NOME, user.nome) put(DatabaseHelper.USER_COL_EMAIL, user.email) put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(user.password)) put(DatabaseHelper.USER_COL_ROLE, user.role) } val rowsAffected = db.update( DatabaseHelper.TABLE_USER, values, "${DatabaseHelper.USER_COL_ID} = ?", arrayOf(user.id.toString()) ) db.close() return rowsAffected }
/** * Deleta um usuário pelo ID. * @param id ID do usuário a deletar * @return Número de linhas afetadas */ fun deleteUser(id: Long): Int { val db = dbHelper.writableDatabase val rowsAffected = db.delete( DatabaseHelper.TABLE_USER, "${DatabaseHelper.USER_COL_ID} = ?", arrayOf(id.toString()) ) db.close() return rowsAffected }
// Simple SHA-256 hash for password storage private fun hashPassword(password: String): String { val md = java.security.MessageDigest.getInstance("SHA-256") val bytes = md.digest(password.toByteArray(Charsets.UTF_8)) return bytes.joinToString("") { "%02x".format(it) } } }
